import React, { useEffect } from "react";
import { Link } from "react-router-dom";
import "../styles/login.css";

const Login = () => {
  const [documento, setDocumento] = useState("");
  const [password, setPassword] = useState("");
  const [codigo, setCodigo] = useState("");
  const [mostrarPassword, setMostrarPassword] = useState(false);
  const [mensajeError, setMensajeError] = useState("");

  const handleSubmit = (e) => {
    e.preventDefault();

    if (!documento || !password || !codigo) {
      setMensajeError("❌ Por favor, complete todos los campos antes de continuar.");
      return;
    }

    setMensajeError("");
    window.location.href = "cuenta.jsx";
  };

  useEffect(() => {
    document.getElementById("year").textContent = new Date().getFullYear();
  }, []);

  return (
    <div className="login-container">
      <h1 className="titulo">inicio</h1>
      <p className="subtitulo">bienvenido a nuestro menú de inicio.</p>

      <form className="formulario" onSubmit={handleSubmit}>
        <label>documento</label>
        <div className="input-box">
          <span className="icon">👤</span>
          <input
            type="text"
            placeholder="XXX.XXX.XXX"
            value={documento}
            onChange={(e) => setDocumento(e.target.value)}
          />
        </div>

        <label>Password</label>
        <div className="input-box">
          <span className="icon">🔒</span>
          <input
            type={mostrarPassword ? "text" : "password"}
            placeholder="••••••••••"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
          <span
            className="eye"
            onClick={() => setMostrarPassword(!mostrarPassword)}
            style={{ cursor: "pointer" }}
          >
            {mostrarPassword ? "🙈" : "👁️"}
          </span>
        </div>

        <label>Código de verificación</label>
        <div className="input-box">
          <span className="icon">💬</span>
          <input
            type="password"
            placeholder="•••"
            maxLength={3}
            value={codigo}
            onChange={(e) => setCodigo(e.target.value)}
          />
        </div>

        {mensajeError && (
          <p style={{ color: "#ff4c4c", fontWeight: "bold", marginBottom: "10px" }}>
            {mensajeError}
          </p>
        )}

        <button type="submit" className="btn">
          Crear una cuenta
        </button>

        <div className="footer">
          <p>
            © <span id="year"></span> Financiero. Todos los derechos reservados.
            Política de seguridad
          </p>
        </div>

        <p className="registro">
          ¿No tienes cuenta? <a href="#">Regístrate aquí.</a>
        </p>
      </form>
    </div>
  );
};

export default Login;
